package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;
import java.lang.reflect.Constructor;
import java.lang.reflect.Field;

class CartTest {

  @Test
  void testGetLineItemsReturnsCorrectList() throws Exception {
    // Create mock LineItem instances using a simple subclass since LineItem class is not found
    class DummyLineItem {}

    Object item1 = new DummyLineItem();
    Object item2 = new DummyLineItem();

    List<Object> items = new ArrayList<>();
    items.add(item1);
    items.add(item2);

    // Use Cart class directly instead of reflection to avoid ClassNotFoundException
    // Create a raw List to pass to constructor (casting to raw List to avoid type issues)
    @SuppressWarnings("unchecked")
    List lineItemsRaw = (List) items;

    // Instantiate Cart with dummy lineItems list, buyerName and creditCard
    Cart cart = new Cart(lineItemsRaw, "buyerName", "creditCard123");

    // Use reflection to set the private final field lineItems to our dummy list (optional here)
    Field lineItemsField = Cart.class.getDeclaredField("lineItems");
    lineItemsField.setAccessible(true);
    lineItemsField.set(cart, lineItemsRaw);

    // Invoke getLineItems method
    @SuppressWarnings("unchecked")
    List<Object> result = (List<Object>) cart.getLineItems();

    assertNotNull(result);
    assertEquals(2, result.size());
    assertSame(item1, result.get(0));
    assertSame(item2, result.get(1));
  }
}
